n><option>WARNING</option><option>NON_COMPLIANT</option><option>NOT_REQUIRED</option></select></div><label class="control-label col-lg-1">Expiring</label><div class="col-lg-1"><select id="filter_expiring_days" class="form-control"><option value="">All</option><option value="30">30</option><option value="60">60</option><option value="90">90</option></select></div><div class="col-lg-2"><input id="filter_keyword" class="form-control" placeholder="<?=hr_h('common_search', 'Search');?>"></div></div><div class="form-group"><div class="col-lg-offset-2 col-lg-10"><button id="btn_filter_cf" class="btn btn-primary"><i class="fa fa-filter"></i> <?=hr_h('common_filter', 'Filter');?></button> <button id="btn_reset_cf" class="btn btn-default"><i class="fa fa-refresh"></i> <?=hr_h('common_reset', 'Reset');?></button></div></div></form></div></div>
