red></div><div class="col-md-2 form-group"><label class="required-label">Valid From</label><input name="valid_from" id="valid_from" class="form-control date-field" value="<?=date('Y-m-d');?>" required></div><div class="col-md-2 form-group"><label>Valid Until</label><input name="valid_until" id="valid_until" class="form-control date-field"></div></div><div class="row"><div class="col-md-2 form-group"><label>Renewal</label><select name="renewal_required" id="renewal_required" class="form-control"><option>N</option><option>Y</option></select></div><div class="col-md-2 form-group"><label>Alert Days</label><input name="renewal_alert_days" id="renewal_alert_days" type="number" class="form-control" value="30"></div><div class="col-md-2 form-group"><label><?=hr_h('common_status', 'Status');?></label><select name="certification_status" id="certification_status" class="form-control"><option>DRAFT</option><option>ACTIVE</option><option>EXPIRING</option><option>EXPIRED</option><option>SUSPENDED</option><option>REVOKED</option><option>RENEWED</option></select></div><div class="col-md-2 form-group"><label>Compliance</label><select name="compliance_status" id="compliance_status" class="form-control"><option>COMPLIANT</option><option>WARNING</option><option>NON_COMPLIANT</option><option>NOT_REQUIRED</option></select></div><div class="col-md-2 form-group"><label><?=hr_h('hr_score', 'Score');?></label><input name="score" id="score" type="number" step="0.01" class="form-control text-right"></div><div class="col-md-2 form-group"><label>File Ref</label><input name="certificate_file_ref" id="certificate_file_ref" class="form-control"></div></div><div class="row"><div class="col-md-12 form-group"><label><?=hr_h('common_remarks', 'Remarks');?></label><textarea name="remarks" id="remarks" class="form-control" rows="3"></textarea></div></div></div><div class="modal-footer"><button type="button" class="btn btn-default" data-dismiss="modal"><?=hr_h('common_cancel', 'Cancel');?></button><button type="submit" class="btn btn-primary"><i class="fa fa-save"></i> Save Certification</button></div></form></div></div></div>
