<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function cfError(m){$('.isi_warning_delete').text(m||'Certification gagal diproses.');$('.error_data_delete').fadeIn();}
function cfFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),certification_type:$('#filter_certification_type').val(),certification_status:$('#filter_certification_status').val(),compliance_status:$('#filter_compliance_status').val(),department_code:$('#filter_department_code').val(),expiring_days:$('#filter_expiring_days').val(),keyword:$('#filter_keyword').val()};}
function cfSetSelect(s,v,t){var e=$(s);if(!v){e.val(null).trigger('change');return;}if(!e.find('option[value="'+v+'"]').length)e.append(new Option(t||v,v,true,true));e.val(v).trigger('change');}
function cfAjaxSelect(s,act,ph,parent){$(s).select2({width:'100%',allowClear:true,placeholder:ph,dropdownParent:parent||$(document.body),ajax:{url:'<?=base_admin();?>modul/certification/certification_action.php?act='+act,type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
function resetCfForm(title){$('#form_certification')[0].reset();$('#cf_id').val('');$('#training_result_id').empty().val(null).trigger('change');$('#issue_date,#valid_from').val('<?=date('Y-m-d');?>');$('#renewal_required').val('N').trigger('change');$('#renewal_alert_days').val('30');$('#certification_status').val('DRAFT').trigger('change');$('#compliance_status').val('COMPLIANT').trigger('change');$('#modal_certification .modal-title').text(title||'Create Certification');$.getJSON('<?=base_admin();?>modul/certification/certification_action.php?act=next_no',function(r){if(r.status==='good')$('#certification_no').val(r.code);});}
$(function(){if($.fn.datepicker){$('.cf-date,.date-field').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_certification_type,#filter_certification_status,#filter_compliance_status,#filter_expiring_days,#certification_type,#renewal_required,#certification_status,#compliance_status').select2({width:'100%',allowClear:true});cfAjaxSelect('#filter_department_code','department_search','Semua Department',$(document.body));cfAjaxSelect('#training_result_id','result_search','Pilih Training Result',$('#modal_certification'));}
var dt=$('#dtb_certification').DataTable({bProcessing:true,bServerSide:true,pageLength:25,order:[[7,'asc']],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'145px',targets:1}],ajax:{url:'<?=base_admin();?>modul/certification/certification_data.php',type:'post',data:function(d){$.extend(d,cfFilters());},dataSrc:function(json){var k=json.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_active').text(k.active||0);$('#kpi_expiring').text(k.expiring||0);$('#kpi_expired').text(k.expired||0);$('#kpi_compliant').text(k.compliant||0);$('#kpi_renewal').text(k.renewal||0);return json.data||[];},error:function(xhr){console.log(xhr.responseText);cfError('Data Certification gagal dimuat.');}}});
$('#btn_open_cf').click(function(){resetCfForm('Create Certification');$('#modal_certification').modal({backdrop:'static',keyboard:false});});$('#btn_filter_cf').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_cf').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_certification_type,#filter_certification_status,#filter_compliance_status,#filter_department_code,#filter_expiring_days').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_cf').click(function(){window.location='<?=base_admin();?>modul/certification/certification_action.php?act=export&'+$.param(cfFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});$('#certification_no').on('keyup change',function(){this.value=this.value.toUpperCase();});
$('#form_certification').submit(function(e){e.preventDefault();var btn=$(this).find('button[type=submit]');btn.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> <?=hr_h('common_saving', 'Saving...');?>');$.post('<?=base_admin();?>modul/certification/certification_action.php?act=save',$(this).serialize(),function(r){btn.prop('disabled',false).html('<i class="fa fa-save"></i> Save Certification');if(r.status==='good'){$('#modal_certification').modal('hide');dt.draw(false);Swal.fire('Saved','Certification berhasil disimpan.','success');}else cfError(r.error_message);},'json').fail(function(xhr){btn.prop('disabled',false).html('<i class="fa fa-save"></i> Save Certification');cfError(xhr.responseText);});});
$(document).on('click','.btn-cf-detail',function(){$.post('<?=base_admin();?>modul/certification/certification_action.php?act=detail',{id:$(this).data('id')},function(html){$('#cf_detail_body').html(html);$('#modal_cf_detail').modal('show');});});
$(document).on('click','.btn-cf-edit',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/certification/certification_action.php?act=get',{id:id},function(r){if(r.status!=='good'){cfError(r.error_message);return;}resetCfForm('Edit Certification');var h=r.data||{};$('#cf_id').val(h.id);$('#certification_no').val(h.certification_no);cfSetSelect('#training_result_id',h.training_result_id,h.result_text);$('#certification_type').val(h.certification_type).trigger('change');$('#certification_name').val(h.certification_name);$('#issuing_body').val(h.issuing_body);$('#certificate_no').val(h.certificate_no);$('#issue_date').val(h.issue_date);$('#valid_from').val(h.valid_from);$('#valid_until').val(h.valid_until);$('#renewal_required').val(h.renewal_required).trigger('change');$('#renewal_alert_days').val(h.renewal_alert_days);$('#certification_status').val(h.certification_status).trigger('change');$('#compliance_status').val(h.compliance_status).trigger('change');$('#score').val(h.score);$('#certificate_file_ref').val(h.certificate_file_ref);$('#remarks').val(h.remarks);$('#modal_certification').modal({backdrop:'static',keyboard:false});},'json');});
$(document).on('click','.btn-cf-renew',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/certification/certification_action.php?act=renew',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire('Renewed','Certification berhasil direnew.','success');}else cfError(r.error_message);},'json');});
$(document).on('click','.btn-cf-delete',function(){var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:erpLang('confirm_delete_title','Delete Confirmation'),text:no,icon:'warning',showCancelButton:true,confirmButtonText:erpLang('common_delete','Delete'),cancelButtonText:erpLang('common_cancel','Cancel')}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/certification/certification_action.php?act=delete',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(erpLang('common_deleted','Deleted'),erpLang('common_deleted_message','Data deleted successfully.'),'success');}else cfError(r.error_message);},'json').fail(function(xhr){cfError(xhr.responseText);});});});
});
</script>
